package com.example.nofiltercoffee; import android.view.*; import android.widget.*; import androidx.recyclerview.widget.*; import java.util.*;
public class QuickActionAdapter extends RecyclerView.Adapter<QuickActionAdapter.VH>{public interface Listener{void onClick(QuickAction a);} ArrayList<QuickAction> list; Listener l; public QuickActionAdapter(ArrayList<QuickAction> list,Listener l){this.list=list;this.l=l;} public VH onCreateViewHolder(ViewGroup p,int v){return new VH(LayoutInflater.from(p.getContext()).inflate(R.layout.item_quick_action,p,false));} public void onBindViewHolder(VH h,int p){QuickAction a=list.get(p);h.i.setText(a.icon);h.t.setText(a.title);h.itemView.setOnClickListener(v->l.onClick(a));} public int getItemCount(){return list.size();} static class VH extends RecyclerView.ViewHolder{TextView i,t;VH(View v){super(v);i=v.findViewById(R.id.txtIcon);t=v.findViewById(R.id.txtTitle);}}}
